async (params, browser) => {
  // Search TikTok
  await browser.open(`https://www.tiktok.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[data-e2e="search_video-item"], .search-card-container', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-e2e="search_video-item"], .search-card-container'); for (let i = 0; i < Math.min(items.length, 10); i++) { const el = items[i]; const descEl = el.querySelector('[data-e2e="search-card-desc"] a, .card-desc a, a[title]'); const creatorEl = el.querySelector('[data-e2e="search-card-user-unique-id"], [data-e2e="creator-uniqueid"], .author-uniqueid, span.creator'); const viewsEl = el.querySelector('[data-e2e="search-card-like-count"], .video-count, strong.view-count'); const likesEl = el.querySelector('[data-e2e="search-card-like-count"], .like-count'); const thumbEl = el.querySelector('img[src*="tiktokcdn"], img.poster, picture img'); const linkEl = el.querySelector('a[href*="/video/"], a[href*="/@"]'); results.push({ description: descEl ? descEl.textContent.trim().substring(0, 300) : '', creator: creatorEl ? creatorEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '', likes: likesEl ? likesEl.textContent.trim() : '', thumbnail: thumbEl ? thumbEl.src : '', url: linkEl ? linkEl.href : '' }); } return { query: '' + params.query + '', result_count: results.length, results: results }`)

  return search_results
}
